-- Zet land op BelgiĆ« voor winkels waar de plaats/stad Belgisch is
-- Uitgebreide lijst van Belgische steden en gemeenten (Nederlands + Frans)
update winkels
set land = 'Belgium'
where trim(coalesce(stad, '')) <> ''
  and lower(trim(stad)) ~ 'brussel|brussels|antwerpen|antwerp|gent|ghent|liĆØge|liege|luik|charleroi|brugge|bruges|namur|namen|leuven|louvain|mons|bergen|aalst|alost|mechelen|malines|kortrijk|courtrai|hasselt|sint-niklaas|genk|roeselare|roulers|dendermonde|termonde|turnhout|dilbeek|heist-op-den-berg|lokeren|vilvoorde|sint-truiden|mouscron|waregem|geel|braine-l''alleud|louvain-la-neuve|louviĆØre|louviere|oudenaarde|audenarde|nieuwpoort|nieuport|diksmuide|ieper|ypres|poperinge|veurne|furnes|koksijde|de panne|knokke|heist|blankenberge|oostende|ostend|zeebrugge|damme|torhout|izegem|menen|wevelgem|zwevegem|tielt|ronse|aarschot|diest|tienen|tirlemont|herentals|mol|lier|willebroek|boom|puurs|bornem|ninove|geraardsbergen|zottegem|evergem|deinze|eecloo|assenede|maldegem|hamme|zele|asse|halle|beersel|drogenbos|linkebeek|watermaal-bosvoorde|ukkel|etterbeek|sint-gillis|sint-joost|schaarbeek|evere|jette|koekelberg|ganshoren|anderlecht|molenbeek|vorst|elsene|oudergem|liege|verviers|seraing|herstal|soumagne|flemalle|ans|saint-nicolas|grace-hollogne|ougree|chenee|sprimont|aywaille|spa|malmedy|stavelot|vielsalm|durbuy|marche-en-famenne|bastogne|arlon|virton|libramont|bouillon|chimay|couvin|philippeville|dinant|ciney|rochefort|beauraing|gedinne|anderlues|binche|manage|morlanwelz|montignies|marcinelle|chatelet|fleurus|gembloux|jodoigne|wavre|nivelles|tubize|waterloo|genappe|ottignies';
